import { auth } from "@/auth";
import { prisma } from "@/lib/prisma";
import { NextResponse } from "next/server";

export async function GET() {
    const session = await auth();

    if (!session?.user) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    if ((session.user as any).role !== "COACH") {
        return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    const user = await prisma.user.findUnique({
        where: { id: session.user.id },
        select: {
            id: true,
            name: true,
            image: true,
        },
    });

    const coachProfile = await prisma.coachProfile.findUnique({
        where: { userId: session.user.id },
        select: {
            id: true,
            title: true,
            shortIntro: true,
            longBio: true,
            expertise: true,
            languages: true,
            yearsOfExperience: true,
        },
    });

    return NextResponse.json({
        user,
        coachProfile,
    });
}

export async function POST(req: Request) {
    const session = await auth();

    if (!session?.user) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    if ((session.user as any).role !== "COACH") {
        return NextResponse.json({ error: "Forbidden" }, { status: 403 });
    }

    try {
        const body = await req.json();
        const {
            name,
            image,
            shortDescription,
            title,
            longBio,
            specialties,
            yearsOfExperience,
            languages,
        } = body;

        if (!image || !String(image).trim()) {
            return NextResponse.json(
                { error: "Lägg till en profilbild" },
                { status: 400 }
            );
        }

        if (!name || !String(name).trim()) {
            return NextResponse.json(
                { error: "Fyll i ditt namn" },
                { status: 400 }
            );
        }

        if (!shortDescription || !String(shortDescription).trim()) {
            return NextResponse.json(
                { error: "Skriv en kort beskrivning" },
                { status: 400 }
            );
        }

        await prisma.user.update({
            where: { id: session.user.id },
            data: {
                name,
                image,
            },
        });

        const expertiseArray: string[] =
            typeof specialties === "string"
                ? specialties
                      .split(",")
                      .map((s: string) => s.trim())
                      .filter(Boolean)
                : Array.isArray(specialties)
                ? specialties
                : [];

        const languagesArray: string[] =
            typeof languages === "string"
                ? languages
                      .split(",")
                      .map((s: string) => s.trim())
                      .filter(Boolean)
                : Array.isArray(languages)
                ? languages
                : [];

        const years =
            typeof yearsOfExperience === "number"
                ? yearsOfExperience
                : yearsOfExperience
                ? Number(yearsOfExperience)
                : null;

        const coachProfile = await prisma.coachProfile.upsert({
            where: { userId: session.user.id },
            update: {
                title: title ?? "",
                shortIntro: shortDescription,
                longBio: longBio ?? "",
                expertise: expertiseArray,
                languages: languagesArray.length > 0 ? languagesArray : ["Svenska"],
                yearsOfExperience: years ?? 0,
                preferredModes: ["VIDEO", "PHONE"],
                isActive: true,
            },
            create: {
                userId: session.user.id,
                title: title ?? "",
                shortIntro: shortDescription,
                longBio: longBio ?? "",
                expertise: expertiseArray,
                languages: languagesArray.length > 0 ? languagesArray : ["Svenska"],
                yearsOfExperience: years ?? 0,
                preferredModes: ["VIDEO", "PHONE"],
                isActive: true,
            },
        });

        return NextResponse.json({
            message: "Profilen sparades",
            coachProfile,
        });
    } catch (error) {
        console.error("Failed to save coach profile", error);
        return NextResponse.json(
            { error: "Kunde inte spara profilen" },
            { status: 500 }
        );
    }
}

